        "type": "code",
        "title": "Policy gate",
        "code": "// Deterministic policy gate \u2014 AI cells estimate, this cell decides.\n// Each input arrives as a JSON-string from a structured-output AI cell.\nconst cost  = JSON.parse(input.Cost);\nconst blast = JSON.parse(input.Blast);\nconst sec   = JSON.parse(input.Security);\n\nconst rules = {\n  cost_delta_under_500_usd: cost.delta_monthly_usd < 500,\n  blast_radius_not_high:    blast.blast_radius !== \"high\",\n  security_risk_below_4:    sec.risk_level < 4,\n};\n\nconst failing = Object.entries(rules)\n  .filter(([, ok]) => !ok)\n  .map(([rule]) => rule);\n\nreturn JSON.stringify({\n  auto_approve: failing.length === 0,\n  human_review_required: failing.length > 0,\n  failing_rules: failing,\n  passing_rules: Object.keys(rules).filter(r => !failing.includes(r)),\n  cost_delta_monthly_usd: cost.delta_monthly_usd,\n  blast_radius: blast.blast_radius,\n  security_risk_level: sec.risk_level,\n}, null, 2);\n",
